[{"language":"lua","description":"Redis Lua 脚本实现原子令牌桶","code":"-- KEYS[1]: rate limit key
-- ARGV[1]: capacity (max tokens)
-- ARGV[2]: refill rate (tokens per second)
-- ARGV[3]: current timestamp (seconds)
-- ARGV[4]: tokens requested
local key = KEYS[1]
local capacity = tonumber(ARGV[1])
local rate = tonumber(ARGV[2])
local now = tonumber(ARGV[3])
local requested = tonumber(ARGV[4])

local bucket = redis.call('HMGET', key, 'tokens', 'last_refill')
local tokens = tonumber(bucket[1]) or capacity
local last_refill = tonumber(bucket[2]) or now

-- Refill tokens based on elapsed time
local elapsed = now - last_refill
tokens = math.min(capacity, tokens + elapsed * rate)

if tokens >= requested then
  tokens = tokens - requested
  redis.call('HMSET', key, 'tokens', tokens, 'last_refill', now)
  redis.call('EXPIRE', key, math.ceil(capacity / rate) * 2)
  return {1, math.floor(tokens), 0}
else
  local retry_after = math.ceil((requested - tokens) / rate)
  return {0, math.floor(tokens), retry_after}
end"},{"language":"typescript","description":"Fastify 限流中间件","code":"export async function rateLimitMiddleware(request: FastifyRequest, reply: FastifyReply) {
  const key = `rl:${request.user?.id ?? request.ip}`;
  const [allowed, remaining, retryAfter] = await tokenBucket(key, {
    capacity: 100,
    rate: 10, // tokens per second
  });

  reply.headers({
    'X-RateLimit-Limit': '100',
    'X-RateLimit-Remaining': remaining.toString(),
    'X-RateLimit-Reset': (Date.now() / 1000 + retryAfter).toFixed(0),
  });

  if (!allowed) {
    reply.header('Retry-After', retryAfter.toString());
    return reply.status(429).send({
      error: 'Too Many Requests',
      retryAfter,
    });
  }
}"}]

