import { join } from 'node:path';

async function initDatabase() {
  // 打包后 WASM 在 extraResources 目录
  const sqlJsOptions = process.env.ELECTRON_PACKAGED
    ? { locateFile: () => join(process.resourcesPath, 'sql-wasm.wasm') }
    : undefined;

  const SQL = await initSqlJs(sqlJsOptions);
  const db = existsSync(DB_PATH)
    ? new SQL.Database(readFileSync(DB_PATH))
    : new SQL.Database();

  db.run('PRAGMA journal_mode = WAL;');
  db.run('PRAGMA foreign_keys = ON;');
  return db;
}"},{"language":"typescript","description":"Prepared Statement 正确用法（含事务批量插入）","code":"// 单条插入
